import{_ as e,c as o,o as d,a as t}from"./app.04967549.js";const r='{"title":"Note","description":"","frontmatter":{},"headers":[{"level":2,"title":"Module Resolution","slug":"module-resolution"},{"level":3,"title":"How Node.js resolves modules","slug":"how-node-js-resolves-modules"}],"relativePath":"docs/typescript/note.md"}',l={},s=[t('<h1 id="note" tabindex="-1">Note <a class="header-anchor" href="#note" aria-hidden="true">#</a></h1><h2 id="module-resolution" tabindex="-1">Module Resolution <a class="header-anchor" href="#module-resolution" aria-hidden="true">#</a></h2><p>There are two possible module resolution strategies: <a href="https://www.typescriptlang.org/docs/handbook/module-resolution.html#node" target="_blank" rel="noopener noreferrer">Node</a> and <a href="https://www.typescriptlang.org/docs/handbook/module-resolution.html#classic" target="_blank" rel="noopener noreferrer">Classic</a>. You can use the <a href="https://www.typescriptlang.org/tsconfig#moduleResolution" target="_blank" rel="noopener noreferrer"><code>moduleResolution</code></a> option to specify the module resolution strategy. If not specified, the default is <a href="https://www.typescriptlang.org/docs/handbook/module-resolution.html#node" target="_blank" rel="noopener noreferrer">Node</a> for <code>--module commonjs</code>, and <a href="https://www.typescriptlang.org/docs/handbook/module-resolution.html#classic" target="_blank" rel="noopener noreferrer">Classic</a> otherwise (including when <a href="https://www.typescriptlang.org/tsconfig#module" target="_blank" rel="noopener noreferrer"><code>module</code></a> is set to <code>amd</code>, <code>system</code>, <code>umd</code>, <code>es2015</code>, <code>esnext</code>, etc.).</p><blockquote><p>Note: <code>node</code> module resolution is the most-commonly used in the TypeScript community and is recommended for most projects. If you are having resolution problems with <code>import</code>s and <code>export</code>s in TypeScript, try setting <code>moduleResolution: &quot;node&quot;</code> to see if it fixes the issue.</p></blockquote><h3 id="how-node-js-resolves-modules" tabindex="-1">How Node.js resolves modules <a class="header-anchor" href="#how-node-js-resolves-modules" aria-hidden="true">#</a></h3><p>To understand what steps the TS compiler will follow, it is important to shed some light on Node.js modules. Traditionally, imports in Node.js are performed by calling a function named <code>require</code>. The behavior Node.js takes will differ depending on if <code>require</code> is given a relative path or a non-relative path.</p><p>Relative paths are fairly straightforward. As an example, let’s consider a file located at <code>/root/src/moduleA.js</code>, which contains the import <code>var x = require(&quot;./moduleB&quot;);</code> Node.js resolves that import in the following order:</p><ol><li>Ask the file named <code>/root/src/moduleB.js</code>, if it exists.</li><li>Ask the folder <code>/root/src/moduleB</code> if it contains a file named <code>package.json</code> that specifies a <code>&quot;main&quot;</code> module. In our example, if Node.js found the file <code>/root/src/moduleB/package.json</code> containing <code>{ &quot;main&quot;: &quot;lib/mainModule.js&quot; }</code>, then Node.js will refer to <code>/root/src/moduleB/lib/mainModule.js</code>.</li><li>Ask the folder <code>/root/src/moduleB</code> if it contains a file named <code>index.js</code>. That file is implicitly considered that folder’s “main” module.</li></ol><p>You can read more about this in Node.js documentation on <a href="https://nodejs.org/api/modules.html#modules_file_modules" target="_blank" rel="noopener noreferrer">file modules</a> and <a href="https://nodejs.org/api/modules.html#modules_folders_as_modules" target="_blank" rel="noopener noreferrer">folder modules</a>.</p><p>However, resolution for a <a href="https://www.typescriptlang.org/docs/handbook/module-resolution.html#relative-vs-non-relative-module-imports" target="_blank" rel="noopener noreferrer">non-relative module name</a> is performed differently. Node will look for your modules in special folders named <code>node_modules</code>. A <code>node_modules</code> folder can be on the same level as the current file, or higher up in the directory chain. Node will walk up the directory chain, looking through each <code>node_modules</code> until it finds the module you tried to load.</p><p>Following up our example above, consider if <code>/root/src/moduleA.js</code> instead used a non-relative path and had the import <code>var x = require(&quot;moduleB&quot;);</code>. Node would then try to resolve <code>moduleB</code> to each of the locations until one worked.</p><ol><li><p><code>/root/src/node_modules/moduleB.js</code></p></li><li><p><code>/root/src/node_modules/moduleB/package.json</code> (if it specifies a <code>&quot;main&quot;</code> property)</p></li><li><p><code>/root/src/node_modules/moduleB/index.js</code></p></li><li><p><code>/root/node_modules/moduleB.js</code></p></li><li><p><code>/root/node_modules/moduleB/package.json</code> (if it specifies a <code>&quot;main&quot;</code> property)</p></li><li><p><code>/root/node_modules/moduleB/index.js</code></p></li><li><p><code>/node_modules/moduleB.js</code></p></li><li><p><code>/node_modules/moduleB/package.json</code> (if it specifies a <code>&quot;main&quot;</code> property)</p></li><li><p><code>/node_modules/moduleB/index.js</code></p></li></ol><p>Notice that Node.js jumped up a directory in steps (4) and (7).</p><p>You can read more about the process in Node.js documentation on <a href="https://nodejs.org/api/modules.html#modules_loading_from_node_modules_folders" target="_blank" rel="noopener noreferrer">loading modules from <code>node_modules</code></a>.</p>',14)];var i=e(l,[["render",function(e,t,r,l,i,n){return d(),o("div",null,s)}]]);export{r as __pageData,i as default};
